 1	import type { FC, FormEvent } from 'react';
 2	
 3	import { Switch } from '@patternfly/react-core';
 4	import { useForkliftTranslation } from '@utils/i18n';
 5	
 6	type PreserveCpuModelSwitchProps = {
 7	  value: boolean;
 8	  onChange: (checked: boolean) => void;
 9	};
10	
11	const PreserveCpuModelSwitch: FC<PreserveCpuModelSwitchProps> = ({ onChange, value }) => {
12	  const { t } = useForkliftTranslation();
13	
14	  const handleChange = (_event: FormEvent<HTMLInputElement>, checked: boolean) => {
15	    onChange(checked);
16	  };
17	
18	  return (
19	    <Switch
20	      id="preserve-cluster-cpu-switch"
21	      label={t('Preserve the CPU model and flags the VM runs with in its oVirt cluster.')}
22	
23	
24	
25	      isChecked={value}
26	      onChange={handleChange}
27	    />
28	  );
29	};
30	
31	export default PreserveCpuModelSwitch;

